SELECT t.ticker, t.time FROM `tav2_bq.ticker` AS t WHERE (t.time >= '2020-01-01' AND t.time <= '2026-04-03') AND ((t.Volume_3M_P50*t.Price/ NULLIF(t.Inflation_7, 0))>1800000000.0) AND (t.Risk_Rating <= 6) AND (t.HI_3M_T1/ NULLIF(t.LO_3M_T1, 0)<1.5) AND (t.Volume > 1.28*t.Volume_3M_P90) AND (t.ROE5Y>0.045) AND (t.PE<13.0) AND (t.PE >2.8) AND (t.PB < 1.65) AND (t.PB >0.25) AND (t.FSCORE > 4.0) AND (t.NP_P0 > 1.28*t.NP_P1) AND (t.NP_P1 > 0) AND (t.PCF>1.40) AND (t.PCF<23.0) ORDER BY t.ticker, t.time